                            "value": {
                              "type": "number"
                            },
                            "unit": {
                              "type": "string",
                              "description": "unit for the dose such as \"g\" "
                            }
                          }
                        },
                        "rateQuantity": {
                          "type": "object",
                          "properties": {
                            "value": {
                              "type": "number"
                            },
                            "unit": {
                              "type": "string",
                              "description": "unit for the rate such as \"h\" "
                            }
